24	use rocket::serde::json::Json;
25	use serde::Serialize;
26	use tracing_subscriber::{fmt, layer::SubscriberExt, util::SubscriberInitExt, EnvFilter};
27	
28	use analytics::handlers::{
29	    create_metric, export, funnel, get_metric, list_metrics, retention, trends, update_metric,
30	};
31	use assets::handlers::{
32	    create_asset, export_assets, get_asset, get_history, import_assets, list_assets, update_asset,
33	    update_status,
34	};
35	use audit::handlers::{get_audit_log, list_audit_logs};
36	use auth::handlers::{catch_unauthorized, login, logout, rotate_password};
37	use backup::handlers::{list_backups, restore_backup, trigger_backup};
38	use billing::handlers::{
39	    add_line, apply_discount, create_invoice, get_invoice, issue_invoice, list_invoices,
40	};
41	use competition::handlers::{
42	    create_event, create_ruleset, get_event, get_ruleset, list_events, list_rulesets,
43	    publish_event, rollback_ruleset, update_event,
44	};
45	use config::AppConfig;
46	use crypto::Cipher;
47	use data_quality::handlers::{get_scan, list_scans, run_scan};
48	use middleware::{correlation::CorrelationFairing, logger::RequestLoggerFairing};
49	use payments::handlers::{
50	    approve_refund, handle_exception, list_exceptions, list_payments, record_payment,
51	    reject_refund, request_refund,
52	};
53	use rbac::handlers::{assign_role, catch_forbidden, list_user_roles, revoke_role};
54	use results::handlers::{
55	    arbitrate_result, export_results, get_rankings, list_corrections, list_reviews,
56	    request_correction, resolve_correction, submit_result, submit_review,
57	};
58	use vehicles::handlers::{
59	    create_vehicle, get_history as get_vehicle_history, get_vehicle, list_vehicles,
60	    transition_status, update_vehicle,
61	};
62	
63	// ── Health check ──────────────────────────────────────────────────────────────
64	
65	#[derive(Serialize)]
66	struct HealthResponse {
67	    status: &'static str,
68	    version: &'static str,
69	}
70	
71	#[get("/health")]
72	fn health() -> Json<HealthResponse> {
73	    Json(HealthResponse {
74	        status: "ok",
75	        version: env!("CARGO_PKG_VERSION"),
76	    })
77	}
78	
79	// ── Entrypoint ────────────────────────────────────────────────────────────────
80	
81	#[rocket::main]
82	async fn main() -> Result<(), rocket::Error> {
83	    dotenvy::dotenv().ok();
84	
85	    // ── Config ────────────────────────────────────────────────────────────────
86	    let app_config = AppConfig::from_env().unwrap_or_else(|e| {
87	        eprintln!("FATAL configuration error: {e}");
88	        std::process::exit(1);
89	    });
90	
91	    // ── Structured logging ────────────────────────────────────────────────────
92	    tracing_subscriber::registry()
93	        .with(EnvFilter::new(&app_config.log_level))
94	        .with(fmt::layer().json().flatten_event(true))
95	        .init();
96	
97	    // ── Crypto key validation ─────────────────────────────────────────────────
98	    let cipher = Cipher::from_base64_key(&app_config.encryption_key).unwrap_or_else(|e| {
99	        tracing::error!(error = %e, "FATAL: encryption key validation failed");
100	        std::process::exit(1);
101	    });
102	
103	    // ── Database ──────────────────────────────────────────────────────────────
104	    let conn = db::connect(&app_config).await.unwrap_or_else(|e| {
105	        tracing::error!(error = %e, "FATAL: database connection failed");
106	        std::process::exit(1);
107	    });
108	
109	    // ── Seed roles ────────────────────────────────────────────────────────────
110	    rbac::seeder::seed_roles(&conn).await.unwrap_or_else(|e| {
111	        tracing::error!(error = %e, "FATAL: role seeding failed");
112	        std::process::exit(1);
113	    });
114	
115	    // ── Seed default users ────────────────────────────────────────────────────
116	    auth::seeder::seed_users(&conn).await.unwrap_or_else(|e| {
117	        tracing::error!(error = %e, "FATAL: user seeding failed");
118	        std::process::exit(1);
119	    });
120	
121	    // ── Nightly backup scheduler ──────────────────────────────────────────────
122	    {
123	        use std::path::PathBuf;
124	        use std::sync::Arc;
125	        backup::scheduler::start(
126	            Arc::new(conn.clone()),
127	            PathBuf::from(&app_config.backup_dir),
128	            app_config.backup_retain_days,
129	        );
130	    }
131	
132	    tracing::info!(
133	        version   = env!("CARGO_PKG_VERSION"),
134	        host      = %app_config.host,
135	        port      = app_config.port,
136	        log_level = %app_config.log_level,
137	        "motorsport-backend starting",
138	    );
139	
140	    // ── Rocket ────────────────────────────────────────────────────────────────
141	    let rocket_cfg = rocket::Config {
142	        address: app_config
143	            .host
144	            .parse()
145	            .unwrap_or_else(|_| "0.0.0.0".parse().unwrap()),
146	        port: app_config.port,
147	        log_level: rocket::config::LogLevel::Off,
148	        ..rocket::Config::default()
149	    };
150	
151	    rocket::custom(rocket_cfg)
152	        .attach(CorrelationFairing)
153	        .attach(RequestLoggerFairing)
154	        .manage(app_config)
155	        .manage(cipher)
156	        .manage(conn)
157	        .mount("/", routes![health, login, logout, rotate_password])
158	        .mount("/", routes![assign_role, revoke_role, list_user_roles])
159	        .mount(
160	            "/",
161	            routes![
162	                create_event,
163	                get_event,
164	                list_events,
165	                update_event,
166	                publish_event,
167	                create_ruleset,
168	                get_ruleset,
169	                list_rulesets,
170	                rollback_ruleset,
171	            ],
172	        )
173	        .mount("/", routes![submit_result, get_rankings, export_results])
174	        .mount(
175	            "/",
176	            routes![
177	                create_vehicle,
178	                get_vehicle,
179	                list_vehicles,
180	                update_vehicle,
181	                transition_status,
182	                get_vehicle_history,
183	            ],
184	        )
185	        .mount(
186	            "/",
187	            routes![
188	                create_asset,
189	                get_asset,
190	                list_assets,
191	                update_asset,
192	                update_status,
193	                get_history,
194	                export_assets,
195	                import_assets,
196	            ],
197	        )
198	        .mount("/", routes![submit_review, list_reviews, arbitrate_result])
199	        .mount(
200	            "/",
201	            routes![request_correction, list_corrections, resolve_correction],
202	        )
203	        .mount(
204	            "/",
205	            routes![
206	                create_invoice,
207	                get_invoice,
208	                list_invoices,
209	                add_line,
210	                apply_discount,
211	                issue_invoice,
212	            ],
213	        )
214	        .mount(
215	            "/",
216	            routes![
217	                record_payment,
218	                list_payments,
219	                handle_exception,
220	                list_exceptions,
221	                request_refund,
222	                approve_refund,
223	                reject_refund,
224	            ],
225	        )
226	        .mount(
227	            "/",
228	            routes![
229	                create_metric,
230	                list_metrics,
231	                get_metric,
232	                update_metric,
233	                trends,
234	                funnel,
235	                retention,
236	                export,
237	            ],
238	        )
239	        .mount("/", routes![run_scan, list_scans, get_scan])
240	        .mount("/", routes![list_audit_logs, get_audit_log])
241	        .mount("/", routes![list_backups, trigger_backup, restore_backup])
242	        .register("/", catchers![catch_unauthorized, catch_forbidden])
243	        .launch()
244	        .await?;
245	
246	    Ok(())
247	}
248	
